  });

  function signMessage(msg: string, secretKey: Uint8Array): string {
    const msgBytes = new TextEncoder().encode(msg);
    const sig = nacl.sign.detached(msgBytes, secretKey);
    return base64js.fromByteArray(sig);
  }

