describe('Cross-cutting invariants', () => {
  it('PILLAR 2: verifySignature is fail-closed (returns false, never throws)', () => {
    // Already tested above but explicit invariant assertion
    expect(verifySignature('', '', '')).toBe(false);
    expect(typeof verifySignature(null as any, null as any, null as any)).toBe('boolean');
  });

  it('PILLAR 2: isExpired is fail-safe (returns true for malformed, never throws)', () => {
    expect(isExpired(undefined as any)).toBe(true);
    expect(isExpired({} as any)).toBe(true);
  });

  it('PILLAR 2: getRebroadcastProbability never throws', () => {
    expect(getRebroadcastProbability(null as any)).toBe(0);
    expect(getRebroadcastProbability({ timestamp: 'bad', ttl: -1 } as any)).toBe(0);
  });

  it('PILLAR 2: isProtocolMessage never throws', () => {
    expect(isProtocolMessage(null).isProtocol).toBe(false);
    expect(isProtocolMessage(123).isProtocol).toBe(false);
    expect(isProtocolMessage(undefined).isProtocol).toBe(false);
  });

  it('PILLAR 4: padding round-trip preserves message bytes', () => {
    const msg = new TextEncoder().encode('{"type":"public","message":"hello"}');
    const roundTripped = unpadMessage(padMessage(msg));
    expect(roundTripped).toEqual(msg);
  });

  it('PILLAR 5: FRAME_SIZES constant is [1024, 4096, 16384, 65536] and frozen', () => {
    expect(FRAME_SIZES).toEqual([1024, 4096, 16384, 65536]);
    expect(Object.isFrozen(FRAME_SIZES)).toBe(true);
    // Verify ascending order
    for (let i = 1; i < FRAME_SIZES.length; i++) {
      expect(FRAME_SIZES[i]).toBeGreaterThan(FRAME_SIZES[i - 1]);
    }
  });

  it('PILLAR 5: getDefaultTTL constants match {direct:300, private:3600, public:86400}', () => {
    expect(getDefaultTTL('direct')).toBe(300);
    expect(getDefaultTTL('private')).toBe(3600);
    expect(getDefaultTTL('public')).toBe(86400);
  });

  it('base64 round-trip identity: decode(encode(x)) === x for arbitrary bytes', () => {
    const sizes = [0, 1, 31, 32, 33, 64, 100, 256];
    for (const size of sizes) {
      const input = new Uint8Array(size);
      if (typeof crypto !== 'undefined' && crypto.getRandomValues) {
        crypto.getRandomValues(input);
      }
      const roundTripped = base64Decode(base64Encode(input));
      expect(roundTripped).toEqual(input);
    }
  });

  it('padding round-trip for all frame size boundaries', () => {
    const boundaries = [0, 1, 1022, 1023, 4094, 4095, 16382, 16383, 65534];
    for (const size of boundaries) {
      const msg = new Uint8Array(size);
      const result = unpadMessage(padMessage(msg));
      expect(result.length).toBe(size);
    }
  });

  it('TTL age clamping: future timestamps result in age=0, not negative', () => {
    vi.useFakeTimers();
    vi.setSystemTime(1000000);
    const futureMsg = { timestamp: Date.now() + 999999, ttl: 300 };
    expect(isExpired(futureMsg)).toBe(false);
    expect(getRemainingTTL(futureMsg)).toBe(300);
    expect(getRebroadcastProbability(futureMsg)).toBeCloseTo(0.6, 2);
    vi.useRealTimers();
  });
});
